\`\`\`rust
impl IdentityMap {
    #[tracing::instrument(level = "trace", skip(self, obj))]
    pub fn insert<T: Model + 'static>(&mut self, obj: T, state: ObjectState) {
        let key = ObjectKey::from(&obj);
        tracing::trace!(
            model = std::any::type_name::<T>(),
            pk_hash = key.pk_hash,
            state = ?state,
            "Inserting into identity map"
        );
        // ...
    }

    pub fn get<T: Model + 'static>(&self, pk: &[Value]) -> Option<&T> {
        let key = ObjectKey::new::<T>(pk);
        let result = self.objects.get(&key)?.get::<T>();
        tracing::trace!(
            model = std::any::type_name::<T>(),
            hit = result.is_some(),
            "Identity map lookup"
        );
        result
    }
}
